class MinStack:
    def __init__(self):
        self.s: list[int] = []         # 主栈
        self.m: list[int] = []         # 最小值栈:m[-1] 始终是当前主栈的最小值

    def push(self, val: int) -> None:
        self.s.append(val)
        # 同步压入「到目前为止的最小值」
        self.m.append(val if not self.m else min(val, self.m[-1]))

    def pop(self) -> None:
        self.s.pop()
        self.m.pop()                   # 两栈同步弹出

    def top(self) -> int:
        return self.s[-1]

    def getMin(self) -> int:
        return self.m[-1]              # O(1) 取最小

examples.explanation:
MinStack minStack = new MinStack();
minStack.push(-2);
minStack.push(0);
minStack.push(-3);
minStack.getMin();   // 返回 -3.
minStack.pop();
minStack.top();      // 返回 0.
minStack.getMin();   // 返回 -2.
